def norm(s):
    s = str(s)
    s = re.sub(r'[ـ]', '', s)
    out=[]
    for ch in s:
        try:
            if unicodedata.combining(unicodedata.normalize('NFD', ch)):
                continue
        except Exception:
            pass
        out.append(ch)
    s=''.join(out)
    s = s.replace('أ','ا').replace('إ','ا').replace('آ','ا').replace('ؤ','و').replace('ئ','ي').replace('ة','ه').replace('ى','ي')
    s = re.sub(r'[^\w\s\u0600-\u06FF]', ' ', s)
    s = re.sub(r'\s+', ' ', s).strip()
    return s

